import { Text as PDFText, View } from '@react-pdf/renderer';
import type { Style } from '@react-pdf/types';
import { usePdfxTheme, useSafeMemo } from '../lib/pdfx-theme-context';
import { createFormStyles } from './pdfx-form.styles';
import type { FormLayout, PdfFormField, PdfFormGroup, PdfFormProps } from './pdfx-form.types';

function renderFieldAbove(
  field: PdfFormField,
  idx: number,
  styles: ReturnType<typeof createFormStyles>
) {
  const areaHeight = field.height ?? 18;
  const areaStyle: Style[] = [styles.fieldArea, { minHeight: areaHeight }];

  return (
    <View key={`${field.label}-${idx}`} style={styles.fieldAbove}>
      <PDFText style={styles.labelAbove}>{field.label}</PDFText>
      <View style={areaStyle}>
        {field.hint ? <PDFText style={styles.hint}>{field.hint}</PDFText> : null}
      </View>
    </View>
  );
}

function renderFieldLeft(
  field: PdfFormField,
  idx: number,
  styles: ReturnType<typeof createFormStyles>
) {
  const areaHeight = field.height ?? 18;
  const areaStyle: Style[] = [styles.fieldArea, styles.fieldLeftArea, { minHeight: areaHeight }];

  return (
    <View key={`${field.label}-${idx}`} style={styles.fieldLeft}>
      <PDFText style={styles.labelLeft}>{field.label}</PDFText>
      <View style={areaStyle}>
        {field.hint ? <PDFText style={styles.hint}>{field.hint}</PDFText> : null}
      </View>
    </View>
  );
}

function renderGroup(
  group: PdfFormGroup,
  gi: number,
  styles: ReturnType<typeof createFormStyles>,
  labelPosition: 'above' | 'left'
) {
  const layout: FormLayout = group.layout ?? 'single';
  const cols = layout === 'three-column' ? 3 : layout === 'two-column' ? 2 : 1;

  const renderField = (field: PdfFormField, idx: number) =>
    labelPosition === 'left'
      ? renderFieldLeft(field, idx, styles)
      : renderFieldAbove(field, idx, styles);

  if (cols === 1) {
    return (
      <View key={`group-${gi}`} style={styles.group}>
        {group.title ? <PDFText style={styles.groupTitle}>{group.title}</PDFText> : null}
        {group.fields.map(renderField)}
      </View>
    );
  }

  const chunkSize = Math.ceil(group.fields.length / cols);
  const chunks: PdfFormField[][] = [];
  for (let i = 0; i < group.fields.length; i += chunkSize) {
    chunks.push(group.fields.slice(i, i + chunkSize));
  }
  while (chunks.length < cols) {
    chunks.push([]);
  }

  return (
    <View key={`group-${gi}`} style={styles.group}>
      {group.title ? <PDFText style={styles.groupTitle}>{group.title}</PDFText> : null}
      <View style={styles.columnsRow}>
        {chunks.map((chunk, ci) => (
          <View key={`col-${gi}-${chunk[0]?.label ?? ci}`} style={styles.column}>
            {chunk.map(renderField)}
          </View>
        ))}
      </View>
    </View>
  );
}

export function PdfForm({
  title,
  subtitle,
  groups,
  variant = 'underline',
  labelPosition = 'above',
  noWrap = false,
  style,
}: PdfFormProps) {
  const theme = usePdfxTheme();
  const styles = useSafeMemo(() => createFormStyles(theme, variant), [theme, variant]);

  const rootStyles: Style[] = [styles.root];
  if (style) rootStyles.push(style);

  const inner = (
    <View style={rootStyles}>
      {title ? <PDFText style={styles.formTitle}>{title}</PDFText> : null}
      {subtitle ? <PDFText style={styles.formSubtitle}>{subtitle}</PDFText> : null}
      {title || subtitle ? <View style={styles.formDivider} /> : null}
      {groups.map((group, gi) => renderGroup(group, gi, styles, labelPosition))}
    </View>
  );

  return noWrap ? <View wrap={false}>{inner}</View> : inner;
}

import { StyleSheet } from '@react-pdf/renderer';
import { usePdfxTheme } from '../lib/pdfx-theme-context';
type PdfxTheme = ReturnType<typeof usePdfxTheme>;
import type { PdfFormVariant } from './pdfx-form.types';

/** Style factory for fillable form layouts, derived from the active theme. */
export function createFormStyles(t: PdfxTheme, variant: PdfFormVariant = 'underline') {
  const { spacing, borderRadius, fontWeights, typography } = t.primitives;
  const borderColor = t.colors.border;
  const hairline = 0.75; // lighter than spacing[0.5]=2pt — more refined
  const rule = 1; // group title rule

  const fieldAreaByVariant: Record<PdfFormVariant, object> = {
    underline: {
      borderBottomWidth: 1,
      borderBottomColor: borderColor,
      borderBottomStyle: 'solid',
    },
    box: {
      borderWidth: hairline,
      borderColor: borderColor,
      borderStyle: 'solid',
      borderRadius: borderRadius.sm,
    },
    outlined: {
      borderWidth: hairline,
      borderColor: t.colors.foreground,
      borderStyle: 'solid',
      borderRadius: borderRadius.md,
    },
    ghost: {
      backgroundColor: t.colors.muted,
      borderRadius: borderRadius.sm,
    },
  };

  const hasPadding = variant === 'box' || variant === 'outlined' || variant === 'ghost';

  return StyleSheet.create({
    root: {
      width: '100%',
      marginBottom: t.spacing.componentGap,
    },

    formTitle: {
      fontFamily: t.typography.heading.fontFamily,
      fontSize: typography.xl,
      lineHeight: t.typography.heading.lineHeight,
      color: t.colors.foreground,
      fontWeight: fontWeights.bold,
      marginBottom: spacing[1],
    },
    formSubtitle: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: typography.sm,
      lineHeight: t.typography.body.lineHeight,
      color: t.colors.mutedForeground,
      marginBottom: spacing[3],
    },
    formDivider: {
      borderBottomWidth: rule,
      borderBottomColor: borderColor,
      borderBottomStyle: 'solid',
      marginBottom: spacing[4],
    },

    group: {
      marginBottom: spacing[5],
    },
    groupTitle: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: typography.xs,
      lineHeight: 1.2,
      color: t.colors.mutedForeground,
      fontWeight: fontWeights.semibold,
      textTransform: 'uppercase',
      letterSpacing: 0.8,
      marginBottom: spacing[3],
    },

    columnsRow: {
      flexDirection: 'row',
      gap: spacing[4],
    },
    column: {
      flex: 1,
    },

    fieldAbove: {
      marginBottom: spacing[3],
      width: '100%',
    },
    labelAbove: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: typography.xs,
      lineHeight: 1.2,
      color: t.colors.mutedForeground,
      fontWeight: fontWeights.medium,
      textTransform: 'uppercase',
      letterSpacing: 0.5,
      marginBottom: spacing[1],
    },

    fieldLeft: {
      flexDirection: 'row',
      alignItems: 'flex-end',
      marginBottom: spacing[3],
      gap: spacing[2],
    },
    labelLeft: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: t.typography.body.fontSize,
      lineHeight: t.typography.body.lineHeight,
      color: t.colors.mutedForeground,
      fontWeight: fontWeights.medium,
      width: 80,
      paddingBottom: hasPadding ? spacing[1] : 0,
    },
    fieldLeftArea: {
      flex: 1,
    },

    fieldArea: {
      width: '100%' as const,
      ...fieldAreaByVariant[variant],
    },

    hint: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: typography.xs,
      color: t.colors.mutedForeground,
      opacity: 0.14,
      paddingTop: hasPadding ? spacing[1] : spacing[0.5],
      paddingBottom: hasPadding ? spacing[1] : 0,
      paddingHorizontal: hasPadding ? spacing[2] : 0,
    },
  });
}

import type { Style } from '@react-pdf/types';

/** Visual style variant for the fillable form. */
export type PdfFormVariant = 'underline' | 'box' | 'outlined' | 'ghost';

/** Column layout for a form section. */
export type FormLayout = 'single' | 'two-column' | 'three-column';

/** Label position relative to the field. */
export type FormLabelPosition = 'above' | 'left';

/**
 * A single fillable field definition.
 * Props - `label` | `hint` | `height` | `width`
 * @see {@link PdfFormField}
 */
export interface PdfFormField {
  label: string;
  hint?: string;
  /**
   * Height of the blank field area in points.
   * @default 18
   */
  height?: number;
  width?: number | string;
}

/**
 * A logical group of fields with an optional section title.
 * Props - `title` | `fields` | `layout`
 * @see {@link PdfFormGroup}
 */
export interface PdfFormGroup {
  title?: string;
  fields: PdfFormField[];
  /**
   * @default 'single'
   */
  layout?: FormLayout;
}

/**
 * Fillable PDF form with grouped fields, layout variants, and label positioning options.
 * Props - `title` | `subtitle` | `groups` | `variant` | `labelPosition` | `noWrap` | `style`
 * @see {@link PdfFormProps}
 */
export interface PdfFormProps {
  title?: string;
  subtitle?: string;
  groups: PdfFormGroup[];
  /**
   * @default 'underline'
   */
  variant?: PdfFormVariant;
  /**
   * @default 'above'
   */
  labelPosition?: FormLabelPosition;
  noWrap?: boolean;
  style?: Style;
}
